@@ -0,0 +1,177 @@
+import React, { useState, useEffect } from 'react';
+import api from '../utils/api';
+import toast from 'react-hot-toast';
+import { FiPackage, FiAlertCircle, FiRefreshCw } from 'react-icons/fi';
+
+const InventoryManagement = () => {
+  const [products, setProducts] = useState([]);
+  const [lowStock, setLowStock] = useState([]);
+  const [showRestockModal, setShowRestockModal] = useState(false);
+  const [selectedProduct, setSelectedProduct] = useState(null);
+  const [restockQuantity, setRestockQuantity] = useState('');
+
+  useEffect(() => {
+    fetchInventory();
+  }, []);
+
+  const fetchInventory = async () => {
+    try {
+      const response = await api.get('/inventory');
+      setProducts(response.data.products);
+      setLowStock(response.data.lowStock);
+    } catch (error) {
+      toast.error('Failed to load inventory');
+    }
+  };
+
+  const handleRestock = async () => {
+    if (!restockQuantity || restockQuantity <= 0) {
+      toast.error('Please enter a valid quantity');
+      return;
+    }
+
+    try {
+      await api.post('/inventory/restock', {
+        productId: selectedProduct.id,
+        quantity: parseInt(restockQuantity)
+      });
+      toast.success(`Successfully restocked ${selectedProduct.name}`);
+      setShowRestockModal(false);
+      setSelectedProduct(null);
+      setRestockQuantity('');
+      fetchInventory();
+    } catch (error) {
+      toast.error('Failed to restock product');
+    }
+  };
+
+  return (
+    <div className="space-y-6">
+      <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Inventory Management</h1>
+
+      {/* Low Stock Alert */}
+      {lowStock.length > 0 && (
+        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4">
+          <div className="flex items-center">
+            <FiAlertCircle className="text-red-600 dark:text-red-400 mr-2" size={24} />
+            <h2 className="text-lg font-semibold text-red-800 dark:text-red-300">
+              Low Stock Alert - {lowStock.length} products need attention
+            </h2>
+          </div>
+        </div>
+      )}
+
+      {/* Inventory List */}
+      <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
+        <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700">
+          <h2 className="text-xl font-semibold text-gray-900 dark:text-white">Current Inventory</h2>
+        </div>
+        <div className="overflow-x-auto">
+          <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
+            <thead className="bg-gray-50 dark:bg-gray-700">
+              <tr>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Product</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Category</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Current Stock</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Min Stock</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Status</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Action</th>
+              </tr>
+            </thead>
+            <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
+              {products.map((product) => {
+                const isLowStock = product.stock <= product.min_stock;
+                return (
+                  <tr key={product.id} className={isLowStock ? 'bg-red-50 dark:bg-red-900/10' : ''}>
+                    <td className="px-6 py-4 whitespace-nowrap">
+                      <div className="flex items-center">
+                        <FiPackage className="mr-2 text-gray-400" />
+                        <span className="text-sm font-medium text-gray-900 dark:text-white">{product.name}</span>
+                      </div>
+                    </td>
+                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-white">{product.category}</td>
+                    <td className="px-6 py-4 whitespace-nowrap text-sm">
+                      <span className={isLowStock ? 'text-red-600 font-semibold' : 'text-gray-900 dark:text-white'}>
+                        {product.stock}
+                      </span>
+                    </td>
+                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-white">{product.min_stock}</td>
+                    <td className="px-6 py-4 whitespace-nowrap">
+                      {isLowStock ? (
+                        <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200">
+                          Low Stock
+                        </span>
+                      ) : (
+                        <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200">
+                          In Stock
+                        </span>
+                      )}
+                    </td>
+                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
+                      <button
+                        onClick={() => {
+                          setSelectedProduct(product);
+                          setShowRestockModal(true);
+                        }}
+                        className="flex items-center text-blue-600 hover:text-blue-900 dark:text-blue-400 dark:hover:text-blue-300"
+                      >
+                        <FiRefreshCw className="mr-1" size={16} />
+                        Restock
+                      </button>
+                    </td>
+                  </tr>
+                );
+              })}
+            </tbody>
+          </table>
+        </div>
+      </div>
+
+      {/* Restock Modal */}
+      {showRestockModal && selectedProduct && (
+        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
+          <div className="bg-white dark:bg-gray-800 rounded-lg p-6 w-full max-w-md">
+            <h2 className="text-2xl font-bold mb-4 dark:text-white">Restock Product</h2>
+            <p className="mb-4 dark:text-gray-300">
+              Current stock of <span className="font-semibold">{selectedProduct.name}</span>: {selectedProduct.stock}
+            </p>
+            <div className="mb-4">
+              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
+                Quantity to add
+              </label>
+              <input
+                type="number"
+                min="1"
+                value={restockQuantity}
+                onChange={(e) => setRestockQuantity(e.target.value)}
+                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:bg-gray-700 dark:text-white"
+                placeholder="Enter quantity"
+                autoFocus
+              />
+            </div>
+            <div className="flex justify-end space-x-3">
+              <button
+                onClick={() => {
+                  setShowRestockModal(false);
+                  setSelectedProduct(null);
+                  setRestockQuantity('');
+                }}
+                className="px-4 py-2 bg-gray-500 text-white rounded-lg hover:bg-gray-600"
+              >
+                Cancel
+              </button>
+              <button
+                onClick={handleRestock}
+                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
+              >
+                Restock
+              </button>
+            </div>
+          </div>
+        </div>
+      )}
+    </div>
+  );
+};
+
+export default InventoryManagement;
